// <guidelines>
// - If `truncated` is true, the content was cut due to size limits — focus on the most relevant section.
// - Binary files (e.g. images, PDFs) are stored at `cached_path` rather than returned inline.
// - Does not execute JavaScript; pages that require it may return incomplete content.
// </guidelines>
type WebFetchArgs struct {
	// Url: Web page URL.
	Url string `json:"url" jsonschema:"Web page URL."`
}

// WebFetchOutput defines the output returned by the "web_fetch" tool.
type WebFetchOutput struct {
	// CachedPath: Cached path in workspace session storage.
	CachedPath string `json:"cached_path,omitempty" jsonschema:"Cached path in workspace session storage."`
	// Content: Web page content.
	Content string `json:"content,omitempty" jsonschema:"Web page content."`
	// IsBinary: Whether the fetched file is binary.
	IsBinary bool `json:"is_binary,omitempty" jsonschema:"Whether the fetched file is binary."`
	// MimeType: Detected MIME type.
	MimeType string `json:"mime_type,omitempty" jsonschema:"Detected MIME type."`
	// Title: Web page title.
	Title string `json:"title,omitempty" jsonschema:"Web page title."`
	// Truncated: Whether the content was truncated due to context limits.
	Truncated bool `json:"truncated,omitempty" jsonschema:"Whether the content was truncated due to context limits."`
	// Url: The fetched URL.
	Url string `json:"url,omitempty" jsonschema:"The fetched URL."`
}

// WebSearchArgs defines the arguments for the "web_search" tool.
//
// Search the web and return a list of results with titles, URLs, and snippets.
//
// <when-to-use>
// - Looking up external libraries, APIs, or tools you are unfamiliar with.
// - Finding documentation, changelogs, or release notes for a dependency.
// - Researching error messages or issues that are not explained by the codebase.
// - Verifying facts or current best practices that may have changed over time.
// </when-to-use>
//
// <guidelines>
// - Results are summaries only — use `web_fetch` on a result URL to retrieve the full page content.
// - Prefer codebase tools (`lsp_inspect`, `grep`, `view`) over web search for anything that can be answered from the project itself.
// </guidelines>
type WebSearchArgs struct {
	// MaxResults: Maximum number of search results to return (default 10, max 20).
	MaxResults int `json:"max_results,omitempty" jsonschema:"Maximum number of search results to return (default 10, max 20)."`
	// Query: Search query.
	Query string `json:"query" jsonschema:"Search query."`
}

// WebSearchOutput defines the output returned by the "web_search" tool.
type WebSearchOutput struct {
	// Results: Search results.
	Results []WebSearchOutputResultsItem `json:"results,omitempty" jsonschema:"Search results."`
}

type WebSearchOutputResultsItem struct {
	// Snippet: Description or snippet of the search result.
	Snippet string `json:"snippet,omitempty" jsonschema:"Description or snippet of the search result."`
	// Title: Title of the search result.
	Title string `json:"title,omitempty" jsonschema:"Title of the search result."`
	// Url: URL of the search result.
	Url string `json:"url,omitempty" jsonschema:"URL of the search result."`
}

// WriteArgs defines the arguments for the "write" tool.
//
// Write content to a file, creating it if it does not exist or overwriting it entirely if it does.
//
// <when-to-use>
// - Creating a new file from scratch.
// - Replacing the entire content of an existing file when most of it is changing.
// </when-to-use>
//
// <guidelines>
// - You MUST `view` the file first when overwriting an existing one — externally modified files will be rejected.
// - For partial changes to an existing file, prefer `edit` or `multi_edit` over a full rewrite.
// </guidelines>
type WriteArgs struct {
	// Content: Content to write.
	Content string `json:"content" jsonschema:"Content to write."`
	// Path: Path to the file.
	Path string `json:"path" jsonschema:"Path to the file."`
}

// WriteOutput defines the output returned by the "write" tool.
type WriteOutput struct {
	// BytesWritten: The number of bytes written to the file.
	BytesWritten int `json:"bytes_written,omitempty" jsonschema:"The number of bytes written to the file."`
	// Diagnostics: LSP diagnostics for this file.
	Diagnostics string `json:"diagnostics,omitempty" jsonschema:"LSP diagnostics for this file."`
	// Path: Path to the written file.
	Path string `json:"path,omitempty" jsonschema:"Path to the written file."`
	// Success: Whether the file was written successfully.
	Success bool `json:"success,omitempty" jsonschema:"Whether the file was written successfully."`
}
